    __guesses: number;
    constructor(mat: number[][]) {
        this.__mat = mat;
        this.__m = mat.length;
        this.__n = mat[0].length;
        this.__guesses = 0;
    }

    get(x: number, y: number): number {
        this.__guesses += 1;
        return this.__mat[x][y];
    }

    getCount(): number {
        return this.__guesses;
    }

    dimensions(): number[] {
        return [this.__m, this.__n];
    }
};"
